column.value:
{
                "pageDescription": "Reporting and REDCap Integration",
                "dataPoints": {
                    "reportGeneration": {
                        "reportType": {
                            "type": "choice",
                            "label": "Report Type",
                            "options": ["Summary Report", "Detailed Results Report", "Quality Control Report", "Statistical Analysis Report", "Audit Trail Report", "Custom Report"],
                            "required": true
                        },
                        "dateRangeStart": {
                            "type": "date",
                            "label": "Date Range Start",
                            "required": false
                        },
                        "dateRangeEnd": {
                            "type": "date",
                            "label": "Date Range End",
                            "required": false
                        },
                        "reportFormat": {
                            "type": "choice",
                            "label": "Report Format",
                            "options": ["PDF", "Excel (XLSX)", "CSV", "JSON"],
                            "required": true
                        },
                        "recipientEmails": {
                            "type": "text",
                            "label": "Recipient Email(s)",
                            "multiline": false,
                            "required": false
                        },
                        "includeAllSamples": {
                            "type": "boolean",
                            "label": "Include All Samples",
                            "required": false
                        }
                    },
                    "externalIntegration": {
                        "redcapProjectId": {
                            "type": "text",
                            "label": "REDCap Project ID",
                            "required": true
                        },
                        "redcapApiToken": {
                            "type": "password",
                            "label": "API Token",
                            "required": false
                        },
                        "recordIdField": {
                            "type": "text",
                            "label": "Record ID Field",
                            "default": "record_id",
                            "required": false
                        },
                        "eventName": {
                            "type": "text",
                            "label": "Event Name (for longitudinal)",
                            "required": false
                        },
                        "instrumentName": {
                            "type": "text",
                            "label": "Instrument Name",
                            "required": false
                        },
                        "validationStatus": {
                            "type": "choice",
                            "label": "Validation Status",
                            "options": ["VALIDATED", "PENDING", "FAILED"],
                            "required": false
                        },
                        "uploadConfirmation": {
                            "type": "boolean",
                            "label": "Upload Confirmation",
                            "required": false
                        }
                    },
                    "archiving": {
                        "archiveLocation": {
                            "type": "text",
                            "label": "Archive Location",
                            "required": false
                        },
                        "archiveNotes": {
                            "type": "text",
                            "label": "Archive Notes",
                            "multiline": true,
                            "required": false
                        },
                        "createBackup": {
                            "type": "boolean",
                            "label": "Create Backup Before Archiving",
                            "default": true,
                            "required": false
                        }
                    }
                },
                "systemActions": [
                    "Generate final report",
                    "Submit data to REDCap",
                    "Validate data before upload",
                    "Archive results",
                    "Maintain full audit trail",
                    "Send email notifications"
                ],
                "bulkOperations": {
                    "enabled": true,
                    "applyToSelected": ["reportType", "reportFormat", "redcapProjectId", "archiveLocation"]
                },
                "workflowCompletion": true
            }
